// Supabase sends the row in body.record (HTTP webhook) or record (realtime)
const record = $json.body?.record ?? $json.record ?? $json;

// Only notify for pending_review inserts — ignore updates and other statuses
if (record.status !== 'pending_review') {
  return [];
}

return [{ json: {
  article_id: record.id,
  title: record.title || 'Untitled',
  category: record.category || 'unknown',
  article_type: record.article_type || 'N/A',
  word_count: record.word_count || 0,
  slug: record.slug || '',
  created_at: record.created_at || new Date().toISOString(),
} }];

